"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["525937"],{234531(e){e.exports=JSON.parse('{"tag":{"label":"multiplayer","permalink":"/dst-api-webdocs/docs/tags/multiplayer","allTagsPath":"/dst-api-webdocs/docs/tags","count":29,"items":[{"id":"game-scripts/components/anchor","title":"Anchor","description":"Manages the raising and lowering state of an anchor attached to a boat, handling drag physics, animation timing, and multiplayer coordination via sailor tasks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/anchor"},{"id":"game-scripts/screens/redux/banspopup","title":"Banspopup","description":"Renders a UI popup screen displaying the list of banned players in the current server session.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/banspopup"},{"id":"game-scripts/screens/redux/cloudserversettingspopup","title":"Cloudserversettingspopup","description":"Manages the UI dialog for configuring settings for cloud server creation, including server name, description, password, privacy type, game mode, max players, and clan-specific options.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/cloudserversettingspopup"},{"id":"game-scripts/components/feasts","title":"Feasts","description":"Manages group coordination, buff application, and announcement logic for winter feast events when multiple players and tables interact.","permalink":"/dst-api-webdocs/docs/game-scripts/components/feasts"},{"id":"game-scripts/widgets/friendsmanager","title":"Friendsmanager","description":"Manages the UI panel for viewing friends, joining parties, and chatting in multiplayer sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/friendsmanager"},{"id":"game-scripts/screens/redux/lobbyscreen","title":"Lobbyscreen","description":"Manages the lobby UI flow during online multiplayer game setup, including character selection, skin loadouts, wait states, and post-match XP/leaderboard panels.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/lobbyscreen"},{"id":"game-scripts/screens/mainscreen","title":"Mainscreen","description":"Manages the main game menu UI, including authentication flow, version checking, and starting local or multiplayer sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/mainscreen"},{"id":"game-scripts/screens/redux/mainscreen","title":"Mainscreen","description":"Manages the main menu screen for Don\'t Starve Together, including UI layout, button handling, authentication flow, and multiplayer session initialization.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/mainscreen"},{"id":"game-scripts/screens/redux/multiplayermainscreen","title":"MultiplayerMainScreen","description":"Main menu screen for Don\'t Starve Together multiplayer mode, providing server browsing, hosting, player summary, and settings navigation with dynamic seasonal banners.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/multiplayermainscreen"},{"id":"game-scripts/networkclientrpc","title":"Networkclientrpc","description":"Defines the complete network RPC system for Don\'t Starve Together, including server-bound, client-bound, and shard-to-shard RPC handlers with queue management and mod extension APIs.","permalink":"/dst-api-webdocs/docs/game-scripts/networkclientrpc"},{"id":"game-scripts/components/oceanfishinghook","title":"Oceanfishinghook","description":"Manages fishing lure behavior and fish attraction mechanics in the ocean, including charm calculation, interest tracking, and reel-based modifiers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oceanfishinghook"},{"id":"game-scripts/playerhistory","title":"PlayerHistory","description":"Manages persistent tracking of player interactions, including playtime and last seen dates, across multiplayer sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/playerhistory"},{"id":"game-scripts/preparedfoods","title":"Preparedfoods","description":"Defines prepared food recipes and their nutritional, status-effect, and inventory behavior in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/preparedfoods"},{"id":"game-scripts/screens/quickjoinscreen","title":"Quickjoinscreen","description":"Manages the UI and logic for automatically searching and joining an appropriate multiplayer server based on user-defined preferences and filtering criteria.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/quickjoinscreen"},{"id":"game-scripts/screens/redux/quickjoinscreen","title":"Quickjoinscreen","description":"Manages automated server search and connection logic for quick join functionality in the multiplayer UI.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/quickjoinscreen"},{"id":"game-scripts/stategraphs/SGplayer_hosted","title":"Sgplayer Hosted","description":"Manages player state transitions for hosted multiplayer sessions, including movement, combat, teleportation, death, and mount-specific behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGplayer_hosted"},{"id":"game-scripts/components/shadowhandspawner","title":"Shadowhandspawner","description":"Spawns shadow hands for players during nighttime when they meet specific conditions, including sanity thresholds, proximity to fire or repairable boats, and vault room restrictions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowhandspawner"},{"id":"game-scripts/components/shard_mermkingwatcher","title":"Shard Mermkingwatcher","description":"Tracks and synchronizes the presence of merm king artifacts (king, trident, crown, pauldron) across shards in multiplayer.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shard_mermkingwatcher"},{"id":"game-scripts/components/shard_players","title":"Shard Players","description":"Tracks and synchronizes the total number of players and ghosts across the local shard and secondary shards in a dedicated server environment.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shard_players"},{"id":"game-scripts/shardnetworking","title":"Shardnetworking","description":"Manages cross-shard network communication, including world connectivity, portal linking, and event synchronization between shards in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/shardnetworking"},{"id":"game-scripts/components/sleepingbag","title":"Sleepingbag","description":"Manages sleep state and associated gameplay effects for entities interacting with a sleeping bag (e.g., healing, hunger loss, sanity restoration).","permalink":"/dst-api-webdocs/docs/game-scripts/components/sleepingbag"},{"id":"game-scripts/prefabs/spawnlight_multiplayer","title":"Spawnlight Multiplayer","description":"A temporary visual FX entity that emits a pulsating light in multiplayer, synchronized across clients with server-authoritative timing and automatic cleanup after fading out.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spawnlight_multiplayer"},{"id":"game-scripts/prefabs/spawnpoint_multiplayer","title":"Spawnpoint Multiplayer","description":"Creates networked spawnpoint entities used in multiplayer world generation, distinguishing between master and non-master spawnpoint instances.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spawnpoint_multiplayer"},{"id":"game-scripts/widgets/teamstatusbars","title":"Teamstatusbars","description":"Manages and displays health status bars for teammates (other players and their pets) in the UI during multiplayer sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/teamstatusbars"},{"id":"game-scripts/widgets/votedialog","title":"Votedialog","description":"Manages the vote UI dialog for player-initiated votes in multiplayer matches, handling visual rendering, animation, and integration with the player voter component and controller screen.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/votedialog"},{"id":"game-scripts/voteutil","title":"Voteutil","description":"Provides utility functions for implementing and resolving player voting systems, including vote result calculation and vote-start validation.","permalink":"/dst-api-webdocs/docs/game-scripts/voteutil"},{"id":"game-scripts/components/wintersfeasttable","title":"Wintersfeasttable","description":"Manages the state and consumption logic for the Winters Eve Feast Table, tracking which entities are feasting and handling food usage.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wintersfeasttable"},{"id":"game-scripts/components/worldcharacterselectlobby","title":"Worldcharacterselectlobby","description":"Manages the lobby state and countdown sequence before players spawn into a world, including tracking player readiness and handling analytics during match startup.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldcharacterselectlobby"},{"id":"game-scripts/components/worldoverseer","title":"Worldoverseer","description":"Tracks player activity, equipment usage, crafting, and session metrics for analytics reporting in multiplayer games.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldoverseer"}],"unlisted":false}}')}}]);